sql:
SELECT a.name, c.category_name
FROM applicants a
INNER JOIN categories c ON a.category_id = c.category_id;

SELECT name, email
FROM interviewers
WHERE interviewer_id IN (SELECT interviewer_id FROM interviews);

SELECT interview_type AS 'Interview Type', AVG(duration) AS 'Average Duration'
FROM interviews
GROUP BY interview_type;

external_knowledge:
- "Travelers" refers to the applicants;
- "Tumultuous seas of application submission and review" symbolizes the statuses 'Submitted' and 'Reviewed';
- "Harbors of categories" represent the different reservation categories applicants are associated with;
- "Navigated through... more than once" implies multiple changes in status.

sql:
SELECT app_id, COUNT(*) as num_applications
FROM applications
GROUP BY app_id;
